-- ============================================================
-- NOTE: To use this seed with real Supabase Auth users,
-- run this SQL after creating accounts to link auth_user_id:
--
--   UPDATE system_users
--   SET auth_user_id = '<real-auth-uuid>'
--   WHERE user_id = '<system-user-uuid>';
--
-- Or use the Supabase Dashboard → Authentication → Users
-- to find the auth UUID after signup.
-- ============================================================
